import { callMcpSkill } from "@/lib/ai/skills/mcp";

export async function main() {
  const toolId = "5cc326fb-500d-4c17-bc5f-ade143210636";

  // 1. Browse the Sports category sorted by volume
  const browseResult = await callMcpSkill({
    toolId,
    toolName: "browse_category",
    args: {
      category: "Sports",
      sortBy: "volume",
      limit: 5,
      status: "open"
    }
  });

  const topMarket = browseResult.markets && browseResult.markets.length > 0 
    ? browseResult.markets[0] 
    : null;

  if (!topMarket) {
    return {
      message: "No active sports markets found.",
      browseResult
    };
  }

  // 2. Cross-reference the top result with Polymarket
  const crossRefResult = await callMcpSkill({
    toolId,
    toolName: "kalshi_crossref_polymarket",
    args: {
      title: topMarket.title,
      keywords: topMarket.title,
      kalshiTicker: topMarket.ticker,
      limit: 3
    }
  });

  return {
    kalshiTopMarket: {
      title: topMarket.title,
      ticker: topMarket.ticker,
      yesPrice: topMarket.yesPrice,
      noPrice: topMarket.noPrice,
      volume24h: topMarket.volume24h,
      url: topMarket.url
    },
    polymarketMatches: crossRefResult.polymarketResults || [],
    comparisonNote: crossRefResult.comparisonNote
  };
}

